css:
.loader {
  color: #ea580c;
width: 45px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color));
background: var(--c),var(--c),var(--c);
background-size: 8px calc(50% + 8px);
-webkit-mask:radial-gradient(circle closest-side,#0000 92%,currentColor) 0/8px 100%;
animation: l11 .75s infinite alternate linear;
}
@keyframes l11 {
0%,
10% {background-position: 0 100%,50% 100%,100% 100%}
25% {background-position: 0 50% ,50% 100%,100% 100%}
50% {background-position: 0 0 ,50% 50% ,100% 100%}
75% {background-position: 0 0 ,50% 0 ,100% 50% }
90%
,100%{background-position: 0 0 ,50% 0 ,100% 0 }
}
